const _props = withDefaults(defineProps<BDropdownFormProps>(), {
  formClass: undefined,
  novalidate: undefined,
  validated: undefined,
  wrapperAttrs: undefined,
})

export function useMergedClsPrefix(): Ref<string> {
  const NConfigProvider = inject(configProviderInjectionKey, null)
  return NConfigProvider
    ? NConfigProvider.mergedClsPrefixRef
    : shallowRef(defaultClsPrefix)
}

const state = computed(() =>
  // Return false (invalid) if new tag is a duplicate
  tags.value.indexOf(newTag.value.trim()) > -1 ? false : null
)

const state = computed(() =>
  // Overall component validation state
  dirty.value ? tags.value.length > 2 && tags.value.length < 9 : null
)

const boundary = computed<Boundary | undefined>(() =>
  isBoundary(props.boundary) ? props.boundary : undefined
)

const computedBlankImgSrc = computed(() =>
  makeBlankImgSrc(computedDimensions.value.width, computedDimensions.value.height, props.blankColor)
)

const click = (place: Placement = 'start') => {
  placement.value = place
  show.value = !show.value
}

interface LabelClasesItemsInput {
  plain?: boolean
  button?: boolean
  buttonVariant?: ButtonVariant | null
  size?: Size
}

interface GroupClassesItemsInput {
  validated?: boolean
  buttons?: boolean
  stacked?: boolean
  size?: Size
}

export interface ElementWithScrollspy extends HTMLElement {
  $__scrollspy?: Record<number, ReturnType<typeof useScrollspy>>
}

if (instance) {
