  delete (elWithProps[propertyName] as Record<string, unknown>)[uid]
}

type BTableProviderContext<T = unknown> = {
  sortBy: BTableSortBy[] | undefined
  filter: string | undefined
  currentPage: number
  perPage: number
}

const tableFieldDefinitions = {
  props: ['prop', 'type', 'default', 'description'],
  emits: ['event', 'args', 'description'],
  slots: ['name', 'scope', 'description'],
  exposed: ['name', 'type', 'description'],
} as const satisfies { [P in ComponentItemFree]: TableFieldRaw[] }

const appDefaults = {
  BButton: {
    variant: 'primary' as const, // This will merge with existing BButton defaults
  },
}

const onFormOverlayShown = () => {
  // Focus on the dialog ok button when the overlay is shown
  successbutton.value?.$el.focus()
}

const handleControlClick = () => {
  // Don't trigger if clicking the button itself (button has its own handler with .stop)
  // Don't trigger if disabled
  if (!props.disabled) {
    openFileDialog()
  }
}

interface PopperEvent extends Event {
  usedByTooltip?: boolean
  closeAllPopover?: boolean
  closePopover?: boolean
}

export const registerElementToInstance = (element, instance) => {
  if (!isVue3) {
    return
  }

  registry.set(element, instance)
}

export const removeElementToInstance = element => {
  if (!isVue3) {
    return
  }

  registry.delete(element)
}
